class FileBud{constructor(){}fileWrapper(e){if(e)return{file:e,name:e.name,type:e.type,download:r=>{const t=URL.createObjectURL(e),l=document.createElement("a");l.download=r||e.name,l.href=t,l.click(),URL.revokeObjectURL(t)},isType:r=>{if(!r)return!1;const t=r=>{r=r.toLowerCase();const t=e.name.toLowerCase(),l=e.type.toLowerCase();return r.startsWith(".")?t.endsWith(r):t.endsWith("."+r)||l===r};return Array.isArray(r)?r.some((e=>t(e))):t(r)},read:(r="text")=>new Promise(((t,l)=>{const i=new FileReader;i.onload=()=>t(i.result),i.onerror=l,"text"===r?i.readAsText(e):"dataURL"===r?i.readAsDataURL(e):"arrayBuffer"===r?i.readAsArrayBuffer(e):l(new Error("Unsupported read type"))}))};console.error("[FileBud] Valid file blob is invalid or empty")}getFileInput(e){const r=document.querySelector(e);return r&&r.files&&r.files[0]?(r.files.length>1&&console.error("[FileBud] The file uploaded is more than one, use getFilesInput for handling this"),this.fileWrapper(r.files[0])):(console.error("[FileBud] The file is unavailable"),null)}getFilesInput(e){const r=document.querySelector(e);return r&&r.files&&r.files[0]?Array.from(r.files).map((e=>this.fileWrapper(e))):(console.error("[FileBud] The file is unavailable"),[])}async getFileInputFromURL(e,r="file"){try{const t=await fetch(e),l=await t.blob(),i=new File([l],r,{type:l.type});return this.fileWrapper(i)}catch(e){return console.error("[FileBud] Failed to fetch file from URL:",e),null}}async getFilesInputFromURL(e){try{return(await Promise.all(e.map((async(e,r)=>{const t=await fetch(e),l=await t.blob(),i=e.split("?")[0].split("#")[0].split("/"),a=i[i.length-1]||i[i.length-2]||`file${r+1}`;return new File([l],a,{type:l.type})})))).map((e=>this.fileWrapper(e)))}catch(e){return console.error("[FileBud] Failed to fetch files from URLs:",e),[]}}}